config.generatedSceneCode:
ctx.lineCap = "round";
ctx.lineJoin = "round";

var P = runtimeState.params || (runtimeState.params = {});
if (P.classSeparation === undefined) P.classSeparation = 6;
if (P.noiseOverlap === undefined) P.noiseOverlap = 2;
if (P.softMarginC === undefined) P.softMarginC = 10;
if (P.rbfGamma === undefined) P.rbfGamma = 1.5;
if (P.showMargins === undefined) P.showMargins = true;
if (P.showSupportVectors === undefined) P.showSupportVectors = true;
if (P.showHeatmap === undefined) P.showHeatmap = false;
if (P.modelMode === undefined) P.modelMode = "Linear";
if (P.showInsetFeatureSpace === undefined) P.showInsetFeatureSpace = true;
if (P.stepIndex === undefined) P.stepIndex = 0;
if (P.infoOpen === undefined) P.infoOpen = -1;

var palette = {
  background: "#0b1020",
  classA: "#22c55e",
  classB: "#60a5fa",
  boundaryPurple: "#a78bfa",
  supportGold: "#fbbf24",
  heatAccent: "#f97316",
  panelBg: "rgba(15, 23, 42, 0.85)",
  panelBorder: "rgba(255, 255, 255, 0.12)",
  text: "#e2e8f0",
  muted: "#94a3b8"
};

var w = canvas.width, h = canvas.height;
var leftPad = 90, rightPad = 380, topPad = 70, bottomPad = 80;
var plot = { x:leftPad, y:topPad, w:Math.max(360, w-leftPad-rightPad), h:Math.max(280, h-topPad-bottomPad) };
var xMin=-10, xMax=10, yMin=-8, yMax=8;
function sx(x){ return plot.x + (x-xMin)/(xMax-xMin)*plot.w; }
function sy(y){ return plot.y + plot.h - (y-yMin)/(yMax-yMin)*plot.h; }
function wx(px){ return xMin + (px-plot.x)/plot.w*(xMax-xMin); }
function wy(py){ return yMin + (plot.y+plot.h-py)/plot.h*(yMax-yMin); }

function rng(i){ var t=Math.sin(i*127.1+311.7)*43758.5453; return t-Math.floor(t); }

if (!runtimeState.svmData) {
  runtimeState.svmData = { A:[], B:[], drag:null, prevDown:false };
}
var D = runtimeState.svmData;

function regen(){
  D.A=[]; D.B=[];
  var n=26;
  for(var i=0;i<n;i++){
    var nx=(rng(i*2.3)-0.5)*(0.8+P.noiseOverlap*0.6);
    var ny=(rng(i*5.7)-0.5)*(2.2+P.noiseOverlap*0.45);
    D.A.push({x:-P.classSeparation*0.55+nx,y:ny,anchor:i<6});
    var mx=(rng(i*7.1)-0.5)*(0.8+P.noiseOverlap*0.6);
    var my=(rng(i*11.9)-0.5)*(2.2+P.noiseOverlap*0.45);
    D.B.push({x:P.classSeparation*0.55+mx,y:my,anchor:i<6});
  }
}
if (!D.seed || D.seedSep!==P.classSeparation || D.seedNoise!==P.noiseOverlap){
  regen(); D.seed=true; D.seedSep=P.classSeparation; D.seedNoise=P.noiseOverlap;
}

var ptr = runtimeState.pointer;
if (ptr && ptr.down) {
  if (!D.drag) {
    var all=D.A.concat(D.B);
    for (var i=0;i<all.length;i++) if (all[i].anchor) {
      var px=sx(all[i].x), py=sy(all[i].y); var rr=10;
      if ((ptr.x-px)*(ptr.x-px)+(ptr.y-py)*(ptr.y-py)<=rr*rr){ D.drag=all[i]; break; }
    }
  }
  if (D.drag){ D.drag.x=Math.max(xMin,Math.min(xMax,wx(ptr.x))); D.drag.y=Math.max(yMin,Math.min(yMax,wy(ptr.y))); }
} else D.drag=null;

var margin = Math.max(0.5, 2.8/(Math.sqrt(P.softMarginC)+0.8));
function fLinear(x,y){ return x; }
function fKernel(x,y){
  var s=0;
  var g=P.rbfGamma*0.18;
  for(var i=0;i<D.A.length;i++){ var dx=x-D.A[i].x, dy=y-D.A[i].y; s += Math.exp(-g*(dx*dx+dy*dy)); }
  for(var j=0;j<D.B.length;j++){ var ex=x-D.B[j].x, ey=y-D.B[j].y; s -= Math.exp(-g*(ex*ex+ey*ey)); }
  return s/8;
}
var f = (P.modelMode==="Kernel") ? fKernel : fLinear;

ctx.strokeStyle="rgba(148,163,184,0.2)"; ctx.lineWidth=1;
for(var gx=-10;gx<=10;gx+=2){ ctx.beginPath(); ctx.moveTo(sx(gx),sy(yMin)); ctx.lineTo(sx(gx),sy(yMax)); ctx.stroke(); }
for(var gy=-8;gy<=8;gy+=2){ ctx.beginPath(); ctx.moveTo(sx(xMin),sy(gy)); ctx.lineTo(sx(xMax),sy(gy)); ctx.stroke(); }
ctx.strokeStyle="rgba(148,163,184,0.5)"; ctx.lineWidth=1.5;
ctx.beginPath(); ctx.moveTo(sx(xMin),sy(0)); ctx.lineTo(sx(xMax),sy(0)); ctx.stroke();
ctx.beginPath(); ctx.moveTo(sx(0),sy(yMin)); ctx.lineTo(sx(0),sy(yMax)); ctx.stroke();

if (P.showHeatmap){
  var nx=70, ny=48;
  for(var ix=0;ix<nx;ix++) for(var iy=0;iy<ny;iy++){
    var xx=xMin+(ix+0.5)/nx*(xMax-xMin), yy=yMin+(iy+0.5)/ny*(yMax-yMin);
    var val=f(xx,yy); var a=Math.min(0.22, Math.abs(val)*0.05+0.03);
    ctx.fillStyle = val>=0 ? "rgba(249,115,22,"+a+")" : "rgba(167,139,250,"+a+")";
    var x0=plot.x+ix/nx*plot.w, y0=plot.y+iy/ny*plot.h;
    ctx.fillRect(x0,y0,plot.w/nx+1,plot.h/ny+1);
  }
}

function drawContour(level,color,dash){
  ctx.strokeStyle=color; ctx.lineWidth=2.6; ctx.setLineDash(dash||[]);
  for(var iy=0;iy<120;iy++){
    var yv=yMin+iy/119*(yMax-yMin);
    var started=false;
    ctx.beginPath();
    for(var ix=0;ix<240;ix++){
      var xv=xMin+ix/239*(xMax-xMin);
      var v=f(xv,yv)-level;
      if (Math.abs(v)<0.08){ var px=sx(xv), py=sy(yv); if(!started){ctx.moveTo(px,py); started=true;} else ctx.lineTo(px,py); }
    }
    if(started) ctx.stroke();
  }
  ctx.setLineDash([]);
}
drawContour(0,palette.boundaryPurple,[]);
if (P.showMargins){ drawContour(margin,palette.boundaryPurple,[8,7]); drawContour(-margin,palette.boundaryPurple,[8,7]); }

function support(pt,cls){ var s=cls*f(pt.x,pt.y); return s<=margin+0.2; }
function drawPoint(pt,color,cls){
  var px=sx(pt.x), py=sy(pt.y); var sv=support(pt,cls);
  ctx.beginPath(); ctx.arc(px,py,pt.anchor?6.2:5,0,Math.PI*2); ctx.fillStyle=color; ctx.globalAlpha=0.95; ctx.fill(); ctx.globalAlpha=1;
  if (P.showSupportVectors && sv){ ctx.lineWidth=3; ctx.strokeStyle=palette.supportGold; ctx.stroke(); }
  if (pt.anchor){ ctx.beginPath(); ctx.arc(px,py,9+Math.sin(time*3+px*0.02)*1.2,0,Math.PI*2); ctx.strokeStyle="rgba(251,191,36,0.25)"; ctx.lineWidth=1.2; ctx.stroke(); }
}
for(var i=0;i<D.A.length;i++) drawPoint(D.A[i],palette.classA,1);
for(var j=0;j<D.B.length;j++) drawPoint(D.B[j],palette.classB,-1);

var controls={x:16,y:16,w:330,h:320};
ctx.fillStyle=palette.panelBg; ctx.strokeStyle=palette.panelBorder; ctx.lineWidth=1;
ctx.beginPath(); ctx.roundRect(controls.x,controls.y,controls.w,controls.h,12); ctx.fill(); ctx.stroke();
ctx.fillStyle=palette.text; ctx.font="10px system-ui, sans-serif"; ctx.textAlign="left";
ctx.fillText("SVM CONTROLS",controls.x+16,controls.y+22);

var hit=[];
function slider(key,label,min,max,y){
  var v=P[key], x=controls.x+16, wv=controls.w-32;
  ctx.fillStyle=palette.muted; ctx.font="11px system-ui, sans-serif"; ctx.textAlign="left"; ctx.fillText(label.toUpperCase(),x,y-8);
  ctx.fillStyle=palette.text; ctx.font="700 11px ui-monospace, monospace"; ctx.fillText(v.toFixed(2),x+wv-48,y-8);
  ctx.strokeStyle="rgba(148,163,184,0.5)"; ctx.lineWidth=2; ctx.beginPath(); ctx.moveTo(x,y+6); ctx.lineTo(x+wv,y+6); ctx.stroke();
  var t=(v-min)/(max-min), kx=x+t*wv;
  ctx.beginPath(); ctx.arc(kx,y+6,6,0,Math.PI*2); ctx.fillStyle=palette.boundaryPurple; ctx.fill();
  hit.push({type:"slider",key:key,min:min,max:max,x:x,y:y-4,w:wv,h:20});
}
slider("classSeparation","Class separation",0,10,60);
slider("noiseOverlap","Noise / overlap",0,10,105);
slider("softMarginC","Soft-margin C",0.1,100,150);
slider("rbfGamma","RBF gamma",0.1,10,195);

function btn(x,y,wv,hv,label,on,kind){
  ctx.fillStyle=on?palette.boundaryPurple:"transparent"; ctx.strokeStyle=palette.panelBorder; ctx.lineWidth=1;
  ctx.beginPath(); ctx.roundRect(x,y,wv,hv,6); ctx.fill(); ctx.stroke();
  ctx.fillStyle=palette.text; ctx.font="11px system-ui, sans-serif"; ctx.textAlign="left"; ctx.fillText(label.toUpperCase(),x+8,y+15);
  hit.push({type:kind,x:x,y:y,w:wv,h:hv,label:label});
}
btn(controls.x+16,230,70,24,"Linear",P.modelMode==="Linear","modeLinear");
btn(controls.x+92,230,110,24,"Kernel (RBF)",P.modelMode==="Kernel","modeKernel");
btn(controls.x+16,262,98,24,"Margins",P.showMargins,"toggleMargins");
btn(controls.x+120,262,130,24,"Support vectors",P.showSupportVectors,"toggleSV");
btn(controls.x+16,292,98,24,"Heatmap",P.showHeatmap,"toggleHeat");

var steps=[
{instruction:"Increase Class separation above 7 and reduce Noise/overlap below 2; keep Linear mode.",concept:"When data is separable, a linear SVM finds a clear separating line with a wide margin.",done:(P.classSeparation>=7 && P.noiseOverlap<=2 && P.modelMode==="Linear")},
{instruction:"Turn Show margins ON and Show support vectors ON; identify the gold-outlined points touching/nearest the dashed lines.",concept:"Support vectors determine the margin; most other points don’t affect the boundary much.",done:(P.showMargins===true && P.showSupportVectors===true)},
{instruction:"Increase Noise/overlap above 6, then sweep Soft-margin C from ≤1 to ≥50 and watch margin violations change.",concept:"Soft-margin SVM trades off margin width vs. training errors; C sets how strict it is about violations.",done:(P.noiseOverlap>=6 && P.softMarginC>=50)},
{instruction:"Switch to Kernel (RBF), then increase RBF gamma above 4 and observe the boundary become more curved/local.",concept:"Kernels enable nonlinear separation; gamma controls boundary complexity.",done:(P.modelMode==="Kernel" && P.rbfGamma>=4)},
{instruction:"Turn Show heatmap/contours ON; locate the f(x)=0 contour and compare deep-color regions vs near-boundary regions.",concept:"Decision function sign gives class; magnitude relates to confidence.",done:(P.showHeatmap===true)}
];
P.stepIndex=Math.max(0,Math.min(steps.length-1,P.stepIndex));
var st=steps[P.stepIndex];

var panel={x:w-350,y:16,w:334,h:250};
ctx.fillStyle=palette.panelBg; ctx.strokeStyle=palette.panelBorder; ctx.beginPath(); ctx.roundRect(panel.x,panel.y,panel.w,panel.h,12); ctx.fill(); ctx.stroke();
ctx.fillStyle=palette.text; ctx.font="10px system-ui, sans-serif"; ctx.textAlign="left"; ctx.fillText("SCAFFOLDED STEPS",panel.x+16,panel.y+22);
ctx.fillStyle=palette.muted; ctx.font="11px system-ui, sans-serif"; ctx.fillText("Step "+(P.stepIndex+1)+" / "+steps.length,panel.x+16,panel.y+40);
function wrap(txt,x,y,maxW,lh,font,color,italic){ ctx.font=(italic?"italic ":"")+font; ctx.fillStyle=color; var words=txt.split(" "),line=""; for(var i=0;i<words.length;i++){ var test=line+words[i]+" "; if(ctx.measureText(test).width>maxW&&line){ ctx.fillText(line,x,y); y+=lh; line=words[i]+" "; } else line=test; } if(line) ctx.fillText(line,x,y); return y+lh; }
var yy=wrap(st.instruction,panel.x+16,panel.y+62,panel.w-32,16,"700 13px system-ui, sans-serif",palette.text,false);
yy=wrap(st.concept,panel.x+16,yy+2,panel.w-32,16,"12px Georgia, 'Times New Roman', serif",palette.muted,true);
ctx.font="700 12px ui-monospace, monospace"; ctx.fillStyle=st.done?"#16A34A":"#DC2626"; ctx.fillText(st.done?"Condition met":"Condition not met",panel.x+16,yy+8);
btn(panel.x+16,panel.y+panel.h-34,34,22,"←",false,"stepPrev");
btn(panel.x+panel.w-50,panel.y+panel.h-34,34,22,"→",false,"stepNext");

var infoPoints=[
{label:"MAX-MARGIN",exp:"The SVM tries to place the boundary so the gap to nearest points is as wide as possible.",x:sx(0.3),y:sy(2.1),c:palette.boundaryPurple},
{label:"DECISION BOUNDARY (f(x)=0)",exp:"Points on this line/curve have equal score for both classes.",x:sx(0.8),y:sy(0.3),c:palette.boundaryPurple},
{label:"MARGINS (f(x)=±1)",exp:"Dashed rails mark the margin around the boundary.",x:sx(1.8),y:sy(1.5),c:palette.boundaryPurple},
{label:"SUPPORT VECTORS",exp:"Closest points (gold outlined) influence the boundary most.",x:sx(-2.8),y:sy(-1.6),c:palette.supportGold},
{label:"SOFT MARGIN (C)",exp:"Low C tolerates violations; high C penalizes them strongly.",x:controls.x+180,y:controls.y+152,c:palette.heatAccent},
{label:"KERNEL (RBF)",exp:"Kernel mode enables curved boundaries; gamma controls locality.",x:controls.x+100,y:controls.y+228,c:palette.heatAccent}
];
for(var ip=0;ip<infoPoints.length;ip++){
  var it=infoPoints[ip]; ctx.fillStyle=it.c; ctx.font="11px system-ui, sans-serif"; ctx.textAlign="left"; ctx.fillText(it.label,it.x,it.y);
  hit.push({type:"info",idx:ip,x:it.x-2,y:it.y-12,w:ctx.measureText(it.label).width+6,h:16});
}

if (ptr && ptr.clicked){
  for(var hi=0;hi<hit.length;hi++){
    var H=hit[hi]; if(ptr.x>=H.x&&ptr.x<=H.x+H.w&&ptr.y>=H.y&&ptr.y<=H.y+H.h){
      if(H.type==="slider"){ var t=Math.max(0,Math.min(1,(ptr.x-H.x)/H.w)); P[H.key]=H.min+t*(H.max-H.min); }
      if(H.type==="modeLinear") P.modelMode="Linear";
      if(H.type==="modeKernel") P.modelMode="Kernel";
      if(H.type==="toggleMargins") P.showMargins=!P.showMargins;
      if(H.type==="toggleSV") P.showSupportVectors=!P.showSupportVectors;
      if(H.type==="toggleHeat") P.showHeatmap=!P.showHeatmap;
      if(H.type==="stepPrev") P.stepIndex=Math.max(0,P.stepIndex-1);
      if(H.type==="stepNext") P.stepIndex=Math.min(steps.length-1,P.stepIndex+1);
      if(H.type==="info") P.infoOpen=H.idx;
    }
  }
}
if (ptr && ptr.down){
  for(var hs=0;hs<hit.length;hs++){ var S=hit[hs]; if(S.type==="slider" && ptr.y>=S.y&&ptr.y<=S.y+S.h&&ptr.x>=S.x&&ptr.x<=S.x+S.w){ var tt=Math.max(0,Math.min(1,(ptr.x-S.x)/S.w)); P[S.key]=S.min+tt*(S.max-S.min);} }
}

if (P.infoOpen>=0){
  var bx=w*0.5-280, by=h-90, bw=560, bh=68;
  ctx.fillStyle=palette.panelBg; ctx.strokeStyle=palette.panelBorder; ctx.beginPath(); ctx.roundRect(bx,by,bw,bh,12); ctx.fill(); ctx.stroke();
  ctx.fillStyle=infoPoints[P.infoOpen].c; ctx.font="11px system-ui, sans-serif"; ctx.textAlign="left"; ctx.fillText(infoPoints[P.infoOpen].label,bx+14,by+20);
  wrap(infoPoints[P.infoOpen].exp,bx+14,by+40,bw-28,15,"12px Georgia, 'Times New Roman', serif",palette.text,true);
}

if (P.modelMode==="Kernel" && P.showInsetFeatureSpace){
  var ix=w-180, iy=h-150, iw=150, ih=110;
  ctx.fillStyle="rgba(15,23,42,0.75)"; ctx.strokeStyle=palette.panelBorder; ctx.beginPath(); ctx.roundRect(ix,iy,iw,ih,10); ctx.fill(); ctx.stroke();
  ctx.strokeStyle=palette.boundaryPurple; ctx.lineWidth=2; ctx.beginPath(); ctx.moveTo(ix+18,iy+85); ctx.quadraticCurveTo(ix+75,iy+20,ix+132,iy+78); ctx.stroke();
  ctx.fillStyle=palette.muted; ctx.font="10px system-ui, sans-serif"; ctx.textAlign="left"; ctx.fillText("FEATURE-SPACE INTUITION",ix+10,iy+16);
}
